import{_ as t,o as r,c as p,ak as o,bA as e,bB as i}from"./chunks/framework.571fwNe4.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"技术/基础软件/企业微信.md","filePath":"技术/基础软件/企业微信.md"}'),l={name:"技术/基础软件/企业微信.md"};function s(c,a,n,d,h,_){return r(),p("div",null,[...a[0]||(a[0]=[o('<p>企业微信（下称企微）是腾讯旗下的办公软件，可以实现和微信互联互通，便于与客户（学生家长）联系交流。</p><h2 id="主要逻辑介绍" tabindex="-1">主要逻辑介绍 <a class="header-anchor" href="#主要逻辑介绍" aria-label="Permalink to “主要逻辑介绍”">​</a></h2><p>首先，企业内部成员均需要下载企业微信，注册账号并加入企业。具体步骤如下：</p><blockquote><p>打开企业微信后左上角两个横杠 -&gt; 创建/加入企业 -&gt; 加入其他企业，会出现二维码。由已经在企微群组中的成员扫描该二维码加入。</p></blockquote><p>此时，企业内部人员建立了在企微的沟通关系（即在企微上，大家都是联系人）。而联系学生家长时，则需要通过企业微信和微信的连接关系来沟通（但是对于学生家长而言，其与在微信中聊天没有区别）。企业微信可以添加外部群，即企业人员以企微身份加入微信群聊。此时，<strong>在微信中我们不可以看到这个群聊</strong>，而在企业微信中则显示为外部群。在微信中，我们企微的账号会显示为 <code>姓名@公司名称</code> 的格式，该群会有企业微信图标（如下图所示）。</p><p><img src="'+e+'" alt=""></p><p><img src="'+i+'" alt=""></p><p>同外部人员的私聊需要以企微身份重新添加，也可以通过微信迁移。</p><p>同企业内部和外部人员的联系尽量通过企微进行。因为群聊迁移后将在微信中消失，仅在企业微信中存在。这样可以很好的隔离个人微信联系人和工作微信联系人。</p><h2 id="页面介绍" tabindex="-1">页面介绍 <a class="header-anchor" href="#页面介绍" aria-label="Permalink to “页面介绍”">​</a></h2><p>在企微初始页面，可以看到多种联系人。其中联系人后不带任何后缀的为企微联系人；有 <code>@微信</code> 的是企微-微信联系人（即你在企微中聊天，对面在微信中看）。同理，不带任何后缀的群聊是企微群聊，有“外部”字样的是微信群。如果你用企微账号加入的微信群，则在对方视角会提示你的企业名称（如下图）： <img src="'+e+'" alt=""></p><p>底栏中有“文档”页面。建议所有的文件使用文档页面进行管理。“工作台”中有许多基础应用，后续会根据需要进行讲解。通讯录记录了在企业中的联系人等。</p><p>在企业微信中的其他操作和微信极其类似，不作赘述。</p><h2 id="需要用到的功能" tabindex="-1">需要用到的功能 <a class="header-anchor" href="#需要用到的功能" aria-label="Permalink to “需要用到的功能”">​</a></h2><h3 id="机器人客服" tabindex="-1">机器人客服 <a class="header-anchor" href="#机器人客服" aria-label="Permalink to “机器人客服”">​</a></h3><p>在工作台 -&gt; 微信客服中可以查看客服账号，点击“客服慧珍”可以展示对于该客服机器人的设置，如欢迎语等，在下面的“工具”中可以看到一些客服工具。</p><p>企微的机器人客服可以实现如下功能：</p><blockquote><p>当客户（学生家长）的询问能够在知识库中找到时，就可以自动匹配和回复。当触发某些关键词或者无法匹配时，就会转为人工。这时，将会由人工来处理信息。可以设置提示词，如“xxx老师正在忙，等她有空时就会回复”等。</p></blockquote><p>“欢迎语”为用户第一次点开机器人的时候的提示，在“机器人-&gt;录入知识库”中可以添加问答，就是高频、热点问题。在“客服慧珍-&gt;接待方式-&gt;接待人员”中可以设置转人工后由谁来回复。在“机器人-&gt;设置-”中可以设置转人工相关的提示词等。</p><h3 id="文档" tabindex="-1">文档 <a class="header-anchor" href="#文档" aria-label="Permalink to “文档”">​</a></h3><p>文档是绝佳的文件管理的方式。可以将所有文档迁移到企微的文档中，便于查找也便于归档，避免丢失。企微还提供了“智能文档”“智能表格”，如有需求，这部分文档再加以完善。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>本文档记录了新方向一站式升学规划所需的企业微信的具体使用流程和基本概念。文档包含范围内的使用可以通过电话（微信同号） 19715430511 询问。其他内容根据需求补充。</p>',23)])])}const f=t(l,[["render",s]]);export{b as __pageData,f as default};
